// Solution
#include <iostream>
#include <unordered_map>
using namespace std;
class Solution {
public:
    int subarray_sum(vector<int>& arr, int target_sum) {
        int sum = 0;
        unordered_map<int, int> prefix_sums;
        for (int i = 0; i < arr.size(); i++) {
            sum += arr[i];
            if (prefix_sums.find(sum - target_sum) != prefix_sums.end()) {
                return 0;
            }
            prefix_sums[sum] = i;
        }
        return 0;
    }
};
int main() {
    Solution s;
    vector<int> arr = {1, 2, 3, 4, 5};
    int target_sum = 10;
    cout << s.subarray_sum(arr, target_sum) << endl;
    return 0;
}

