// Solution
import java.util.HashMap;
import java.util.Map;
public class Solution {
public:
    int subarray_sum(int[] arr, int target_sum) {
        int sum = 0;
        Map<Integer, Integer> prefix_sums = new HashMap<>();
        for (int i = 0; i < arr.length; i++) {
            sum += arr[i];
            if (prefix_sums.containsKey(sum - target_sum)) {
                return 0;
            }
            prefix_sums.put(sum, i);
        }
        return 0;
    }
public static void main(String[] args) {
    Solution s = new Solution();
    int[] arr = {1, 2, 3, 4, 5};
    int target_sum = 10;
    System.out.println(s.subarray_sum(arr, target_sum));
}

